-- כלכלית לוד
UPDATE public.clients SET
  business_description = E'כלכלית לוד היא פלטפורמת החדשות הכלכלית-עסקית של לוד — עיר שנמצאת במהפך היסטורי.\n\nהמספרים מדברים: עלייה של 40% בעסקים חדשים ב-5 השנים האחרונות. עלייה של 30% במשפחות צעירות. 5,544 היתרי בנייה ב-2024 בלבד. 9,447 יחידות דיור בבנייה. הסכם גג של 8.5 מיליארד ₪ עם הממשלה. רכבת קלה לת"א בדרך. מחירי דיור נמוכים ב-30% מפ"ת ומודיעין.\n\nהפלטפורמה מכסה את המהפך הזה: השקות עסקים, יזמים ערבים ויהודים שבונים יחד, פרויקטי "לודקיישן" (מרכז תעסוקה), שכונות נופי בן שמן והרובע הבינלאומי. המשימה: לוד צריכה קול כלכלי רציני — וכלכלית לוד הוא הקול הזה.',
  target_audience = E'שלושה סגמנטים:\n(1) בעלי עסקים ויזמים בלוד ובסביבתה (28–55) — ערבים ויהודים — שרוצים חשיפה ומידע על הזדמנויות\n(2) משקיעים ויזמים חיצוניים שמסתכלים על לוד כהזדמנות (נדל"ן, לוגיסטיקה, תעסוקה)\n(3) תושבים בעלי מודעות כלכלית שגאים בעיר ורוצים לעקוב אחרי השינוי\nכולם: השכלה גבוהה, עניין בפיתוח קהילתי, כוח קנייה בינוני-גבוה',
  competitors = 'לוד נט (חדשות מקומיות כלליות — לא ייעוד עסקי), קהילות פייסבוק עסקיות לא מנוהלות, תקשורת עסקית ארצית (TheMarker, גלובס) שלא מכסה לוד לעומק. **כלכלית לוד היא המקום היחיד לחדשות כלכליות ממוקדות-לוד.**',
  tone = E'קול של מי שמאמין שלוד הולכת להפתיע את כולם — ויש לנו את הנתונים להוכיח.\n\n• מקצועי ואופטימי — לא PR שטחי, לא ביקורת שחורה\n• עובדות ומספרים ראשית, אווירה שנייה — "40% עסקים חדשים" > "לוד מתפתחת"\n• סיפורים אישיים של יזמים = הלב של התוכן. הנתון + הפנים = מגנט\n• מרחב לשני הקהלים: ערבי ויהודי — שניהם בונים את לוד\n• FOMO לגיטימי: "מי שמסתכל על לוד עכשיו יגיד \'הייתי שם ראשון\'"\n• CTA: "ספרו לנו", "מכירים מישהו שצריך לדעת?", "שתפו יזמים בסביבתכם"',
  design_notes = 'עיצוב נקי ומקצועי: ירוק כהה, לבן, אפור. אינפוגרפיקות למספרים (carousel). תמונות: פנים של יזמים, בנייה פעילה, שלטי עסקים חדשים — לא לוד "עם בעיות" אלא לוד בתנועה. לוגו עיר + נוף עירוני מתחדש. תמונות "לפני ואחרי" של מקומות עסקיים.',
  do_not_post = 'תכנים פוליטיים מפלגתיים. ביקורת על עסקים ספציפיים ללא בסיס עובדתי. תכנים שמחריפים מתחים עדתיים — כלכלית לוד היא גשר. "לוד הסכנות" כל תוכן שמשמר את הסטיגמה הישנה. מחירים ומידע לא מאומת.',
  seasonal_events = 'ינואר: "לוד 2024 בסיכום" — דוח כלכלי שנתי עם נתונים (עסקים חדשים, היתרי בנייה). מרץ: ירידי אביב, פסח — כיצד עסקים מקומיים מתכוננים. מאי: "לוד 2025 — כך בונים" (מאמרי עומק). ספטמבר: פתיחת שנת עסקים — אחרי חגים תמיד שיא השקות. נובמבר: בלאק פריידי — עסקים מקומיים מול רשתות גדולות. כל השנה: השקות עסקים חדשים, אירועי רשת יזמים, הודעות על פרויקטי תשתית.',
  writing_examples = E'🏗️ לפני שלוש שנים זה היה מחסן נטוש ברחוב ויצמן. היום — מסעדה שעוצרת תנועה בשישי.\n\nחוסיין ואבי, שכנים מ-20 שנה, פתחו יחד את "מטבח לוד" — מטבח משותף, ערבי ויהודי, שמייצר 200 מנות ליום.\n"אנחנו ההוכחה שלוד מוכנה לזה. רק צריך אנשים שיאמינו ראשונים."\n\n📍 מכירים עסק מקומי שמספרו צריך להישמע? שלחו לנו 👇\n#כלכלית_לוד #יזמות #לוד_מתפתחת\n\n📊 לוד 2025 בנתונים:\n• 40% יותר עסקים חדשים ב-5 שנים\n• 9,447 יחידות דיור בבנייה פעילה\n• מחיר דיור: 30% נמוך יותר מפ"ת ומודיעין\n• הסכם גג: 8.5 מיליארד ₪ מהממשלה\n• מרחק: 8 ק"מ מנתב"ג — יתרון לוגיסטי ייחודי\n\nמי שמסתכל על לוד עכשיו יגיד בעוד 5 שנים: "הייתי שם ראשון."\n📈 הניתוח המלא בלינק בביו\n#לוד #כלכלה_מקומית #LodBusiness',
  brand_hashtags = '#כלכלית_לוד #לוד #עסקים_בלוד #יזמות_לוד #כלכלה_מקומית #LodBusiness #לוד_מתפתחת #לוד2025',
  content_pillars = '[
    {"name":"סיפורי יזמים ועסקים — פנים + נתון + השראה","percentage":30},
    {"name":"לוד בנתונים — אינפוגרפיקות כלכליות ועסקיות","percentage":25},
    {"name":"נדל\"ן, תשתיות ופרויקטי פיתוח (רכבת, שכונות)","percentage":20},
    {"name":"הזדמנויות: מענקים, כנסים, רשתות עסקים","percentage":15},
    {"name":"קהילה — חיבורים ערבי-יהודי, שותפויות מקומיות","percentage":10}
  ]'::jsonb,
  social_channels = '[
