-- ספארי רמת גן
UPDATE public.clients SET
  business_description = E'ספארי רמת גן — המרכז הזואולוגי הגדול במזרח התיכון. 700,000+ מבקרים בשנה.\n\nמתחם ייחודי: (1) ספארי מכוניות — נסיעה בשטח פתוח בין ~1,550 בעלי חיים מ-200 מינים (83 יונקים, 92 ציפורים, 23 זוחלים). (2) גן חיות מגוון על שטח 1,000 דונם. (3) בית חולים לחיות בר — מטפל ב-2,000+ חיות בשנה (פועל מ-2005). ייחודים עולמיים:\n\n• יוסי — הפיל הגדול ביותר בעולם בגני חיות. נולד 11.8.1974 בספארי (ילד ראשון!). גובה: 3.8 מ\'. משקל: ~8 טון. 32 צאצאים בעולם (רוב בבריטניה). מפורסם עולמית — מטפלי פילים מגיעים מחו"ל רק לפגוש אותו. יום ההולדת שלו: יום לפני יום הפיל הבינלאומי (12.8).\n• 34 קרנפים לבנים נולדו בספארי — תוכנית שימור מהמצליחות עולמית. האחרון: "רעי", שנולד לריהאנה.\n• 60 תוכניות שימור בינלאומיות: גורילות גב המישור, חתולי חול, פילים אסייתיים ואפריקאיים.\n• "לילות ספארי" — סיורי לילה עונתיים (אפריל–ספטמבר).\n• ספארי אוזניות — מדריך שמע אינטראקטיבי חדש.',
  target_audience = E'ארבעה סגמנטים:\n(1) משפחות עם ילדים 2–14 — שבת או חופש. הורים 25–45 שרוצים חוויה שמחנכת ומרגשת.\n(2) מחנכים ובתי ספר — טיול שנתי. הספארי מוכר ב-Cito.\n(3) תיירים — ספארי רמת גן הוא אטרקציה בינלאומית (אנשי חיות מחו"ל מגיעים רק לראות את יוסי).\n(4) צעירים ובני נוער — לילות ספארי, תוכן TikTok.\nכולם: אוהבי טבע, בינוני-גבוה כלכלית, ממרכז הארץ בעיקר.',
  competitors = 'גן לאומי, חוות פרפרים, לגו-לנד, פארק הירדן — אך ספארי רמת גן הוא קטגוריה בפני עצמה. **הפיל הגדול בעולם בגני חיות נמצא אצלנו — אין לזה מתחרה.**',
  tone = E'קול של מי שחי עם החיות — ומספר את הסיפורים שלהן בשם.\n\n• כל חיה = דמות עם שם, אישיות, היסטוריה. לא "פיל בפארק" — "יוסי, שנולד ב-1974 ועדיין שומר על הכותרת"\n• פליאה > ריגוש. "ידעת ש..." > "בואו תראו"\n• שימור = גאווה, לא כובד. "34 קרנפים שנולדו כאן — זה לא פחות ממהפכה"\n• Reels ספונטניים של רגעי יומיום — להאכיל, לשחק, להתמתח, לנגח — הם הוויראליים ביותר\n• לילות ספארי = FOMO: "אתם יודעים מה האריות עושים בשעה 11 בלילה?"\n• CTA: "בואו לפגוש" ולא "קנו כרטיס"',
  design_notes = 'ירוקים אפריקאיים, חומים, זהב. וידאו ספונטני > צילום מבוים. מקרוב: עיניים, טקסטורת עור, פרווה, חדקים. Reels קצרים עם עובדה מדהימה ב-text overlay. תמונות משפחה מבעד לחלון המכונית. ילדה מסתכלת על קרנף = ויראלי. תמיד: שמות החיות בכיתוב.',
  do_not_post = 'חיות בסבל, פציעות, מוות. ביקורת על פארקים אחרים. פוליטיקה. תמונות ציד. בריחת חיה (פאניקה). ביקורות על שבי/כלוב — תמיד להפנות לתוכניות השימור ולא להתגונן רגשית.',
  seasonal_events = E'ינואר-פברואר: "ספארי בגשם" — עומסים נמוכים, חיות פעילות בקרנה. תוכן שלא רואים בקיץ.\nמרץ-אפריל: פסח — הסזון הגדול בשנה. 700K מבקרים בשנה — הרבה מהם בפסח. להזמין מראש!\nאפריל: "לילות ספארי" חוזרים (עד ספטמבר) — FOMO קיץ.\nאפריל 22: יום כדור הארץ — "60 תוכניות שימור, כי זה מה שאנחנו עושים".\nאוגוסט 11: יום הולדת יוסי! — תוכן ויראלי מובטח. "הפיל הגדול בעולם חוגג".\nאוגוסט 12: יום הפיל הבינלאומי — continuation של אוגוסט 11.\nספטמבר 22: יום הקרנף הבינלאומי — "34 קרנפים שנולדו כאן".\nחנוכה-חורף: "ספארי לילה" + אירוע חג לילדים.',
  writing_examples = E'🐘 יוסי נולד ב-11 באוגוסט 1974. כלומר — הוא יותר ותיק בספארי מרוב המבקרים שלנו.\n\nהיום יוסי שוקל כ-8 טון ומתנשא ל-3.8 מטרים — מה שהופך אותו לפיל הגדול ביותר בעולם בגני חיות מאז 2006.\nיש לו 32 צאצאים. רובם בבריטניה. מטפלי פילים מגיעים מהעולם כולו רק לפגוש אותו.\n\nומה הוא עושה? מטייל לאט. אוכל. מסתכל על המבקרים בעיניים שרואות הכל.\nתבואו להסתכל בחזרה 🐘\n\n📍 ספארי רמת גן | כרטיסים ושעות בלינק בביו\n#יוסי #ספארי_רמת_גן #פיל #PiLargest\n\n🦏 ריהאנה ילדה ב-3 לפנות בוקר. בשעה 5 "רעי" כבר עמד.\n\nזהו קרנף לבן מספר 34 שנולד בספארי רמת גן — חלק מאחת מתוכניות הרבייה המוצלחות ביותר בעולם לסוג זה.\nבתחילת המאה ה-20 היו מאות אלפים. בשיא המשבר — 20 בלבד. כיום: 18,000.\nלכל אחד מ-34 הקרנפים שנולדו כאן יש חלק בזה.\n\n💪 שימור טבע הוא לא תיאוריה — זה רעי, שישן עכשיו ליד אמא.\n#קרנף #שימור_טבע #ספארי',
  brand_hashtags = '#ספארי_רמת_גן #ספארי #RamatGanSafari #יוסי_הפיל #חיות_בר #שימור_טבע #Israel_Safari #לילות_ספארי',
  content_pillars = '[
    {"name":"כוכבי הפארק — יוסי, רעי ואחרים — עובדות + רגשות","percentage":30},
    {"name":"רגעים ספונטניים — Reels יומיומיים של חיי הפארק","percentage":25},
    {"name":"שימור מינים — סיפורי הצלחה, תוכניות, גאווה","percentage":20},
    {"name":"אירועים ועונות — לילות ספארי, פסח, ימים בינלאומיים","percentage":15},
    {"name":"UGC ומאחורי הקלעים — צוות, וטרינרים, מטפלים","percentage":10}
  ]'::jsonb,
  social_channels = '[
    {"platform":"instagram","posts_per_week":6},
    {"platform":"tiktok","posts_per_week":5},
    {"platform":"facebook","posts_per_week":4}
