-- קרטרס
UPDATE public.clients SET
  business_description = E'קרטרס ישראל — "המותגים לתינוקות וילדים שמשגעים את ישראל."\n\nזכיינית ישראלית של Carter''s, מותג ביגוד הילדים הגדול בארה"ב (נוסד 1865 — מעל 160 שנה של מוניטין). 72 חנויות בישראל בתוך רשת H&O + אונליין בcartersoshkosh.co.il.\n\nשני מותגים: Carter''s (0–8) + OshKosh B''Gosh (2–8, ג''ינס וסרבלים). הפלטפורמה מוכרת גם Skip Hop ו-Little Planet.\n\nמה הם מוכרים: בגדי יומיום, פיג''מות (הבסטסלר!), בגדי חג, בגדי ים, נעליים, ערכות מתנה ללידה. מחיר: 80–500₪. מבצע אייקוני: 3 ב-99₪. Black Friday: עד 70% הנחה.\n\nאינסטגרם: @cartersisrael — 30K עוקבים.',
  target_audience = 'אמהות ואבות לתינוקות וילדים בגילאי 0–8, גיל 25–42. מעמד בינוני-גבוה. שני סגמנטים: (1) הורים שקונים לעצמם — חיפוש איכות ועיצוב. (2) קונים לשמחות — ברית, בר-מצווה, ימי הולדת, מתנות ל"יולדת". הסגמנט השני חשוב מאוד — קרטרס הוא מתנת הלידה הנפוצה בישראל.',
  competitors = 'זארה קידס, גאפ קידס, שילב ישראל, פוקס בייבי — אך קרטרס מוביל בסגמנט "הורה שרוצה איכות אמריקאית" ב-0–24 חודשים',
  tone = E'חמימות אמריקאית של 160 שנה — עם לב ישראלי.\n\nקרטרס מדברת עם הורה שכבר עייף מהיום, ועדיין מחייך כשהוא רואה את הצ''ופרים ישנים בפיג''מה. הטון: אמפתי, שמח, לא מתאמץ. הומור הורי שלא מכוון — הוא פשוט קורה.\n\n3 פורמולות תוכן שעובדות לקרטרס:\n1. "רגע יומיום" + מוצר: ילד מסרב להוריד פיג''מה → קישור לפיג''מה\n2. "מה לקנות ל[שמחה]" — ברית, יולדת, יום הולדת ראשון\n3. UGC — תמונת לקוח + "שלחו לנו תמונות" — מייצר engagement אמיתי\n\n• גוף שני: "את", "אתה" — לא "הורים"\n• "שלכם לראות", "הצצה ראשונה" — תמיד FOMO עדין\n• מבצע 3 ב-99₪ = הפורמט שכולם מחכים לו\n• Black Friday: ה-event — לבנות ציפייה שבועיים לפני',
  design_notes = 'פלטת צבעים: אדום קרטרס הקלאסי, לבן, צהוב חמניה, תכלת. צילומי lifestyle — תינוקות וילדים בסיטואציות אמיתיות: בוקר, אמבטיה, גן, משחק. תמונות בהירות ומאווררות. הרבה תמונות UGC של לקוחות — זה ה-DNA של המותג. עיצוב clean אמריקאי.',
  do_not_post = 'ביגוד של מתחרים. תמונות ילדים ללא אישור מהורים. תכנים שעלולים לעורר ויכוח פרנטינג (חיסונים, הנקה, CIO). תוכן פוליטי. מחירים ישנים שלא תקפים. "פרסי אמא הכי טובה" — לא שיפוטי.',
  seasonal_events = 'ינואר: סייל גדול — חיסול חורף וחיתולים גדולים. פברואר: ולנטיינס — מתנות לתינוקות ולאמהות. מרץ-אפריל: קולקציית אביב + בגדי חג לפסח (ברית וחג ביחד = עומס). מאי: יום האם — "המתנה הכי טובה לאמא צעירה". אוגוסט: Back to School + סייל קיץ. ספטמבר: ראש השנה — בגדי חג לילדים + ברית בחגים. נובמבר: בלאק פריידי — ה-event הגדול. דצמבר: חנוכה + מתנות.',
  writing_examples = E'😴 היא ישנה 3 שעות.\nהוא ישן 20 דקות וכבר דורש ארוחת בוקר.\nשניהם נראים מושלמים בפיג''מות החדשות 💛\n\nקולקציית "Little Dreams" הגיעה — ומביאה איתה בד הכי רך שיש.\nכי הפיג''מה הזו תעבור 100 כביסות ועדיין תראה כמו חדשה. זה הלינק בביו 👇\n#קרטרס #CartersIsrael #פיג''מות_תינוקות\n\n🎁 מה קונים ל"יולדת"?\nלא פרחים שיגמרו אחרי שלושה ימים.\nקרטרס — כי כשיש תינוק חדש בבית, הכי טוב לתת לו משהו שיצחיק את אמא בבוקר 👶😍\n\n3 חליפות, 5 רומפרים, ו-2 כובעי כותנה שאי אפשר שלא לצלם.\n\n🛍️ ערכות מתנה מוכנות לשליחה — לינק בביו\n#קרטרס #מתנת_לידה #ברית #יולדת',
  brand_hashtags = '#קרטרס #קרטרס_ישראל #CartersIsrael #בגדי_תינוקות #בגדי_ילדים #אמא_ותינוק #Carters #OshKosh',
  content_pillars = '[
    {"name":"קולקציות חדשות ומוצרים בסגנון lifestyle","percentage":30},
    {"name":"UGC – תמונות תינוקות של לקוחות בבגדי קרטרס","percentage":20},
    {"name":"תוכן הורי – רגעים, הומור וחיי יומיום","percentage":20},
