-- סקיפ הופ
UPDATE public.clients SET
  business_description = E'סקיפ הופ ישראל — אביזרים חכמים ועיצוביים לתינוקות ופעוטות. נמכרים גם דרך cartersoshkosh.co.il (אותה פלטפורמה כמו קרטרס). אינסטגרם: @skiphopisrael — 1,240 עוקבים, 622 פוסטים.\n\nקטגוריות עיקריות:\n(1) קולקציית Zoo — הפרודוקט הכי מפורסם: תיקי גב עם דמויות חיות (שועל, דוב, ינשוף, כלב, דבורה, ועוד) לגיל 1.5–4. גם תיק גן לגיל 3–5. פופולרי כמתנת כניסה לגן.\n(2) תיקי חיתולים — Chelsea ואחרים. כיסים מרובים, בקבוק מבודד, עיצוב minimal.\n(3) אביזרי האכלה — כוסות Sip (מפתחות שרירי פה לדיבור), צלחות עם יניקה, כפיות למידה עצמי.\n(4) צעצועי פיתוח מוטורי ומוסיקלי.\n(5) אביזרי שינה, בטיחות, ומוניטורים.\n\nהייחוד: כל מוצר = עיצוב (יפה בסלון) + פונקציה (עובד ב-3 לפנות בוקר) + פיתוח (מקדם את הילד).',
  target_audience = 'הורים לתינוקות ופעוטות בגילאי 0–3, עצמם בגילאי 25–38. שני סגמנטים: (1) הורים "design-aware" שרוצים שהאביזרים ייראו טוב בסלון. (2) מחפשי איכות — "רוצה שזה יעבוד ויחזיק". שניהם: כוח קנייה גבוה. גם: קונים לבייבי שאוור — תיק Zoo הוא מתנת לידה קלאסית.',
  competitors = 'Ergobaby ישראל, Chicco ישראל, Nuna בישראל, Munchkin — סקיפ הופ מוביל בסגמנט "עיצוב + פונקציה" לפעוטות',
  tone = E'חכמה רגועה של הורה שהתחיל להבין מה עובד — ומוצר שחישב הכל מראש.\n\n3 פורמולות תוכן שעובדות לסקיפ הופ:\n1. "למה תוכנן ככה?" — חשיפת הלוגיקה מאחורי המוצר: "הכוס עגולה מלמטה כי..."\n2. "מה צריך לגיל X?" — מדריך carousel שמקבל saves ושיתופים\n3. Zoo collection showcase — "איזה חיה הוא?" + poll → engagement טבעי\n\n• לא "תקנו" — "תגלו למה זה עובד"\n• Minimal aesthetic גם בטקסט: משפט אחד חד, ולא פסקה\n• "הם לא יגידו לך מה לקנות לבייבי שאוור — אנחנו כן"\n• Zoo = שמות חיות = engagement: "שועל, ינשוף, דוב — מי הכי פופולרי אצלכם?"\n• Reel פיתוח: "היא לא שותה מכוס. עד שקנינו..." — הורה מספר, לא מותג',
  design_notes = 'פלטת צבעים: כתום Zoo, ירוק מינט, אפור חם, לבן. אסתטיקה מינימליסטית ונקייה. Flat-lay מסודר של מוצרים על רקע לבן/עץ טבעי. תמונות lifestyle: תינוק משתמש במוצר בסביבה ביתית חמה. אור טבעי. ללא עומס.',
  do_not_post = 'מוצרים פגומים, ביקורות שליליות ללא מענה, תמונות לא בטיחותיות של תינוקות, מידע רפואי שאינו מאושר, מחירים שגויים.',
  seasonal_events = 'ינואר-פברואר: מוצרי חורף — מעילים לגב, בגדי שכבות. מרץ-אפריל: "עונת הבייבי שאוור" — אביב = לידות. מאי: יום האם — מתנות פרמיום לאמא חדשה. יוני-יולי: אביזרי קיץ, צלחות צבעוניות, כוסות חינוך. ספטמבר-אוקטובר: פתיחת גנים — תיקי Zoo חוזרים. נובמבר: בלאק פריידי — ה-event הגדול. כל רבעון: קולקציה חדשה.',
  writing_examples = E'🦊 [POLL] איזו חיה הילד שלכם?\n• שועל 🦊\n• דוב 🐻\n• ינשוף 🦉\n• דבורה 🐝\n\nתיקי Zoo חזרו לחנות — 12 דמויות, לגיל 1.5–4, עם כיס מבודד לבקבוק ואופציה לרקום שם.\nהצביעו 👇 (ואז לכו לבדוק שיש את שלכם בלינק בביו)\n#סקיפהופ #SkipHop #Zoo #תיק_גן\n\n📊 [CAROUSEL] "מה לקנות לתינוק בגיל X?" — המדריך שחיסך לנו 20 שיחות\n\nגיל 0–3 חודשים: [מוצרים]\nגיל 3–6 חודשים: [מוצרים]\nגיל 6–9 חודשים: [מוצרים]\nגיל 9–12 חודשים: [מוצרים]\nגיל 1+: Zoo תיק גב\n\nשמרו את הפוסט — תצטרכו אותו 👇\n#סקיפהופ #מדריך_לתינוק #הורות_מודעת #SkipHopIsrael',
  brand_hashtags = '#סקיפהופ #SkipHop #SkipHopIsrael #Zoo_Collection #אביזרי_תינוקות #הורות_מודעת #בייבי_גיר #מתנת_לידה',
  content_pillars = '[
    {"name":"הצגת מוצרים בסגנון lifestyle – Zoo ותיקי גב","percentage":30},
    {"name":"חינוך – למה המוצר תוכנן ככה (פיתוח תינוקות)","percentage":25},
    {"name":"מדריכי רכישה – מה צריך לגיל X","percentage":20},
    {"name":"מתנות לידה ובייבי שאוור","percentage":15},
    {"name":"מבצעים ו-UGC","percentage":10}
  ]'::jsonb,
