-- רולדין (tone inspired by Ruthy Brudo competitor analysis)
-- ⚠️ CORRECTION: Roladin founded 1987 (concept) / 1989 (first store, Ramat HaSharon). NOT 1962. 111 branches in Israel + 2 in London (2025).
UPDATE public.clients SET
  business_description = E'רולדין — רשת הקונדיטוריות ובתי הקפה הגדולה ביותר בישראל: 111 סניפים בפריסה ארצית + 2 בלונדון (2023).\n\nנוסדה ב-1989 על ידי האחים קובי ואבי חקק, שהחלו ב-1987 במכירת עוגות בית מדלת לדלת ברמת השרון. היום: מאפייה מרכזית בקדימה, 150+ סוגי מאפים יומיים בעבודת יד, קפה איטלקי, עוגות מיוחדות, קרואסונים, לחמים. גם ספק עוגות לאל-על וחברת Tnuva.\n\nחנוכה = האירוע הגדול ביותר: קמפיינים שנתיים של סופגניות עם ממדי אמנות בינלאומיים (שיתוף פעולה עם צייר גוף Johannes Stötter, קמפיין "Opposites Attract" 4 שנים ברצף). בריטניה פתחה ב-2023 תחת המותג Donutelier.',
  target_audience = 'נשים וגברים בגילאי 22–60, אוהבי קולינריה ופינוקים איכותיים. משפחות לאירועים וחגים, זוגות לעוגות אירוסין וחתונה, בעלי עסקים להזמנות קייטרינג. מעמד בינוני-גבוה, מוכנים לשלם פרמיום על איכות אמיתית.',
  competitors = 'רותי ברודו (בייקרי TLV – בוטיק, 5 סניפים, מיצוב יוקרה-אוטנטי), לחמים (רשת פרמיום), ארקפה (קפה-מאפייה בוטיק), Dr. Lek',
  tone = E'ערוץ: פייסבוק בלבד — תוכן מבוסס קמפיינים ממוקדי מסר ותוצאה. לא פוסטים יומיומיים שגרתיים — כל פוסט הוא חלק מקמפיין עם מטרה ברורה (מכירה, מודעות, הזמנות, חג).\n\nשפת המלאכה + החגיגה הישראלית — זה ה-DNA של רולדין.\n\nהסיסמה הפנימית: "הכל התחיל לפני 36 שנה, והשאר היסטוריה שנאפית כל בוקר מחדש."\n\nלקחנו שיעור מרותי ברודו: הם מוכרים סיפור של ידיים, לא מוצר. גם אנחנו — אבל עם הנשמה הרולדינית: חמימות, שמחה, ישראליות.\n\n• עברית עשירה וחושנית: ריחות, מרקמים, זיכרון, בית\n• שפת "אנחנו" — הלקוח שותף למסורת, לא צרכן\n• מלאכה ולא ייצור: "נאפה הבוקר", "הידיים שלנו", "בעבודת יד"\n• חנוכה = ספקטקל שנתי: 4 סדרות, שיתופי פעולה עם עולם האמנות והאופנה\n• חגיגיות ישראלית עם עומק — לא "קנו עכשיו" — "טעמו לפני שייגמר"\n• כל פוסט הוא מהלך: קמפיין חג, לאנץ\' מוצר, הנעה להזמנה\n• אין SALE זול — יש "הגיעה הקולקציה"',
  design_notes = 'פלטת צבעים: אדום-ענבר, זהב, קרם ולבן שמנת. צילומים קרובים ומגרים: קרואסון שבור שמגלה שכבות חמאה, שוקולד שנמס לאט, קצפת שנמשכת. אור זהוב ורך — מטבח, לא סטודיו. ידיים של אומן — לא ידיים מדגמניות. תאורה חמה. אסתטיקה של בית-מאפייה צרפתי שחי בלב ישראל.',
  do_not_post = 'תמונות לא מוצלחות של מוצרים, מוצרים פגומים, שיח על דיאטה ופחדי השמנה, תכנים פוליטיים, השוואה לרשתות מזון מהיר, תוכן שאינו כשר, מחירים שהשתנו. אין "SALE" אגרסיבי — רולדין היא פרמיום.',
  seasonal_events = E'פברואר 14: יום האהבה — עוגות לב, "לאחד שנמס עליך".\nפורים (מרץ): המן-טאשן בטעמים מיוחדים + עוגות פורים.\nפסח: קולקציית ללא חמץ — עוגות, עוגיות, מרנגים.\nשבועות: עוגות גבינה — "עונת הגבינה של רולדין".\nראש השנה (ספטמבר): ערכות מתנה, עוגות דבש-תפוח, "שנה מתוקה מרולדין".\nחנוכה = האירוע השנתי הגדול ביותר:\n  • 4 סדרות: הקלאסיות (8₪), העננים (16₪ — בצק אוורירי חדש), האייקוניות (18₪), הפטיסרי (20₪)\n  • כל שנה: שיתוף עם אמן/מעצב (2022: צייר גוף Johannes Stötter, 2025: המעצב מאור צבר)\n  • FOMO: "לפני שייגמרו"\nכריסמס/סילבסטר: עוגות חגיגה ל-31.12.',
  writing_examples = E'🥐 זה לא קרואסון — זה 27 שכבות של סבלנות.\n\nמ-4 בבוקר, הידיים של האופה שלנו מקפלות בצק עם חמאה. שוב ושוב. שכבה על שכבה.\nאת הריח של החמאה שנמסת בתנור אי אפשר לזייף.\nוגם לא את הסיפור שמאחורי זה.\n\nאצלנו — כל בוקר מחדש. 36 שנה ולא עצרנו. 🧡\n\n📍 111 סניפים | לינק בביו\n#רולדין #קרואסון #מלאכת_אפייה #Roladin\n\n🕎 השנה הן שונות.\n\nסדרת "העננים" — סופגניות מבצק חדש שפיתחנו חצי שנה.\nהביס הראשון מרגיש כמו שם — קל, אוורירי, ועם מילוי שלא מפסיק להפתיע.\n\nשוקולד סוכרה. מרנג פטל. דולצ\'ה בננה.\nוסדרת הפטיסרי — לאלה שרוצים את כל ה-La Sabrine.\n\nהאנשים שלנו עבדו עליהן מיולי. שלכם לטעום — לפני שייגמרו. 🤫\n\n📍 111 סניפים | #חנוכה #סופגניות_רולדין #רולדין',
  brand_hashtags = '#רולדין #Roladin #מאפיית_רולדין #מלאכת_אפייה #קונדיטוריה_ישראלית #פינוק_איכותי #קרואסון #סופגניות_רולדין',
  content_pillars = '[
